function [frcCnt,rAx,frcPk,rng] = fSptRdlAnlV01(img,x,y,nmbStp,edgPix)% Perform spot analysis, fractional counts as a function of radius%% [frcCnt,rAx] = fSptRdlAnlV01(x,y,img,nmbStp,edgPix)% x: axis information (x axis)% y: counts for each point (yaxis)% img: source image% nmbStp: number of steps for output% edgPix: number of pixels in edges to evaluate noise level%% frcCnt: fractional counts as a function of r% rAx: radius% frcPk: fractional peak count / pixel size, to evaluate fluence% rng: considered radial range for image%%%%%%%%%%%%%%%%%%%%%%%%%%%%%% Function spot radial analysis, ver.1%% Kei Nakamura% Created on Friday, February 19th 2010.% Modified on %% ver.1: created%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main body% for ROI x[szy,szx] = size(img);aaa = sum(img); % integrate in ybbb = mean([aaa(1:edgPix),aaa(end-edgPix+1:end)]);  % mean of edgeccc = bbb/max(aaa); % noise/signal ratio[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:szx],aaa,ccc);xs = round(peak-wLIn);  % x start pixelxe = round(peak+wHIn);  % x end pixel% for ROi yddd = sum(img,2)';  % integrate in xeee = mean([ddd(1:10),ddd(end-edgPix+1:end)]);fff = eee/max(ddd);[wHIn,wLIn,wHOut,wLOut,peak] = fGetFwAnyMaxV01([1:szy],ddd,fff);ys = round(peak-wLIn);  % y startye = round(peak+wHIn);  % y endroiImg = img(ys:ye,xs:xe);  % roi-ed imageroiX = x(xs:xe);  roiY = y(ys:ye);% to check% figure% subplot(1,2,1)% pcolor(roiX,roiY,roiImg)% shading interp% colorbar% 2D interpolation to match up with stepsrng = max(abs([roiX,roiY]));    % range for rstp = rng/nmbStp;   % step for pixelintpX = [roiX(1):stp:roiX(end)];    % interporated xintpY = [roiY(1):stp:roiY(end)];    % interporated yintpImg = interp2(roiX,roiY,roiImg,intpX,intpY');    % interporated image% to chech% subplot(1,2,2)% pcolor(intpX,intpY,intpImg)% shading interp% colorbar% r-calculation[mshX,mshY] = meshgrid(intpX,intpY);mshR = sqrt(mshX.^2+mshY.^2);   % radius matrixrAx = [stp:stp:rng]; % r-axis for calculationrLgc = mshR<=rng;       % consider pixels within the rangettlCnts = sum(sum(rLgc.*intpImg));   % evaluate total counts within the rangekk = 1;for r = rAx;   % 1 to rng(range) micron    frcCnt(kk) = sum(sum(intpImg.*(mshR<r)));    % ttl counts within r      kk = kk + 1;endfrcCnt = frcCnt/ttlCnts;  % normalized ttl count as function of rpeak = max(max(intpImg));disp([roiX(end),intpX(end)]);frcPk = peak/ttlCnts;   % fractional peak countfrcPk = frcPk/(stp*stp);    % normalized by pixel size
